1	/* ast.h -- AST node types and pool for PL/SW compiler */
2	/* Uses parallel arrays instead of structs (tc24r workaround) */
3	
4	#ifndef AST_H
5	#define AST_H
6	
7	#include "arena.h"
8	
9	/* Node kind constants */
10	#define NODE_NONE          0
11	#define NODE_PROGRAM       1
12	#define NODE_DCL           2
13	#define NODE_PROC          3
14	#define NODE_IF            4
15	#define NODE_DO_WHILE      5
16	#define NODE_DO_COUNT      6
17	#define NODE_ASSIGN        7
18	#define NODE_BINOP         8
19	#define NODE_UNOP          9
20	#define NODE_CALL         10
21	#define NODE_RETURN       11
22	#define NODE_LITERAL      12
23	#define NODE_IDENT        13
24	#define NODE_ASM_BLOCK    14
25	#define NODE_FIELD_ACCESS 15
26	#define NODE_ARRAY_ACCESS 16
27	#define NODE_ADDR         17
28	#define NODE_DEREF        18
29	#define NODE_BLOCK        19
30	#define NODE_PARAM        20
31	
32	/* Type info constants */
33	#define TYPE_NONE    0
34	#define TYPE_INT8    1
35	#define TYPE_INT16   2
36	#define TYPE_INT24   3
37	#define TYPE_BYTE    4
38	#define TYPE_CHAR    5
39	#define TYPE_BIT     6
40	#define TYPE_WORD    7
41	#define TYPE_PTR     8
42	#define TYPE_ARRAY   9
43	#define TYPE_RECORD  10
44	
45	/* Storage class constants */
46	#define STOR_AUTO     0
47	#define STOR_STATIC   1
48	#define STOR_EXTERNAL 2
49	#define STOR_BASED    3
50	
51	/* Null node index sentinel */
52	#define NODE_NULL (-1)
53	
54	/* Node pool -- parallel arrays, 256 nodes max */
55	#define NODE_POOL_MAX 256
56	
57	int nd_kind[NODE_POOL_MAX];       /* node kind */
58	int nd_type[NODE_POOL_MAX];       /* type info */
59	int nd_stor[NODE_POOL_MAX];       /* storage class */
60	int nd_level[NODE_POOL_MAX];      /* DCL level (1,3,5,...) */
61	int nd_left[NODE_POOL_MAX];       /* left child index */
62	int nd_right[NODE_POOL_MAX];      /* right child index */
63	int nd_next[NODE_POOL_MAX];       /* sibling/next index */
64	int nd_ival[NODE_POOL_MAX];       /* integer value or operator */
65	char *nd_name[NODE_POOL_MAX];     /* name (arena-allocated) */
66	
67	int nd_count;                     /* number of allocated nodes */
68	
69	void ast_init(void) {
70	    nd_count = 0;
71	}
72	
73	/* Allocate a new node. Returns node index or NODE_NULL on OOM. */
74	int nd_alloc(int kind) {
75	    if (nd_count >= NODE_POOL_MAX) {
76	        return NODE_NULL;
77	    }
78	    int i = nd_count;
79	    nd_count = nd_count + 1;
80	    nd_kind[i]  = kind;
81	    nd_type[i]  = TYPE_NONE;
82	    nd_stor[i]  = STOR_AUTO;
83	    nd_level[i] = 0;
84	    nd_left[i]  = NODE_NULL;
85	    nd_right[i] = NODE_NULL;
86	    nd_next[i]  = NODE_NULL;
87	    nd_ival[i]  = 0;
88	    nd_name[i]  = 0;
89	    return i;
90	}
91	
92	/* Set the name on a node (copies string into arena) */
93	void nd_set_name(int n, char *name) {
94	    if (n < 0 || n >= nd_count) return;
95	    int len = str_len(name);
96	    char *s = arena_alloc(len + 1);
97	    if (s) {
98	        str_copy(s, name);
99	        nd_name[n] = s;
100	    }
101	}
102	
103	/* Append child to end of a node's sibling chain via nd_next */
104	void nd_append(int parent, int child) {
105	    if (parent < 0 || child < 0) return;
106	    /* Find the appropriate child slot */
107	    if (nd_left[parent] == NODE_NULL) {
108	        nd_left[parent] = child;
109	        return;
110	    }
111	    /* Walk the sibling chain from left child */
112	    int cur = nd_left[parent];
113	    while (nd_next[cur] != NODE_NULL) {
114	        cur = nd_next[cur];
115	    }
116	    nd_next[cur] = child;
117	}
118	
119	/* Create a literal node */
120	int nd_literal(int value) {
121	    int n = nd_alloc(NODE_LITERAL);
122	    if (n != NODE_NULL) {
123	        nd_ival[n] = value;
124	        nd_type[n] = TYPE_INT24;
125	    }
126	    return n;
127	}
128	
129	/* Create an identifier node */
130	int nd_ident(char *name) {
131	    int n = nd_alloc(NODE_IDENT);
132	    if (n != NODE_NULL) {
133	        nd_set_name(n, name);
134	    }
135	    return n;
136	}
137	
138	/* Create a binary operator node */
139	int nd_binop(int op, int left, int right) {
140	    int n = nd_alloc(NODE_BINOP);
141	    if (n != NODE_NULL) {
142	        nd_ival[n] = op;
143	        nd_left[n] = left;
144	        nd_right[n] = right;
145	    }
146	    return n;
147	}
148	
149	/* Create a unary operator node */
150	int nd_unop(int op, int operand) {
151	    int n = nd_alloc(NODE_UNOP);
152	    if (n != NODE_NULL) {
153	        nd_ival[n] = op;
154	        nd_left[n] = operand;
155	    }
156	    return n;
157	}
158	
159	/* Create an assignment node */
160	int nd_assign(int target, int value) {
161	    int n = nd_alloc(NODE_ASSIGN);
162	    if (n != NODE_NULL) {
163	        nd_left[n] = target;
164	        nd_right[n] = value;
165	    }
166	    return n;
167	}
168	
169	/* Create a CALL node */
170	int nd_call(char *name, int args) {
171	    int n = nd_alloc(NODE_CALL);
172	    if (n != NODE_NULL) {
173	        nd_set_name(n, name);
174	        nd_left[n] = args;
175	    }
176	    return n;
177	}
178	
179	/* Create a RETURN node */
180	int nd_return(int expr) {
181	    int n = nd_alloc(NODE_RETURN);
182	    if (n != NODE_NULL) {
183	        nd_left[n] = expr;
184	    }
185	    return n;
186	}
187	
188	/* Return a human-readable name for a node kind */
189	char *nd_kind_name(int kind) {
190	    if (kind == NODE_PROGRAM)       return "PROGRAM";
