189	/* Parse a level-based record declaration.
190	   Called after DCL and the first level number have been consumed.
191	   Syntax: DCL 1 NAME, 3 FIELD TYPE, 3 FIELD TYPE, ...;
192	
193	   Level 1 = record container, 3+ = fields.
194	   Lower level numbers start new groups. */
195	int parse_dcl_record(int first_level) {
196	    /* Parse the record name */
197	    if (cur_type != TOK_IDENT) {
198	        parse_error("expected record name");
199	        return NODE_NULL;
200	    }
201	
202	    /* Create record container node */
203	    int rec = nd_alloc(NODE_DCL);
204	    if (rec == NODE_NULL) {
205	        parse_error("node pool full");
206	        return NODE_NULL;
207	    }
208	    nd_set_name(rec, cur_text);
209	    nd_type[rec] = TYPE_RECORD;
210	    nd_level[rec] = first_level;
211	    parse_advance();
212	
213	    /* Parse optional storage class on record itself */
214	    nd_stor[rec] = parse_storage();
215	
216	    /* Expect comma or semicolon after record name */
217	    if (!parse_match(TOK_COMMA)) {
218	        /* Record with no fields -- just a named type */
219	        parse_expect(TOK_SEMI);
220	        return rec;
221	    }
222	
223	    /* Parse fields: level NAME type, ... ; */
224	    while (!parse_err) {
225	        /* Expect a level number */
226	        if (cur_type != TOK_NUM) {
227	            parse_error("expected level number");
228	            return rec;
229	        }
230	        int field_level = cur_ival;
231	        parse_advance();
232	
233	        /* Parse the field */
234	        int field = parse_dcl_field(field_level);
235	        if (field == NODE_NULL) return rec;
236	
237	        /* Append field as child of record */
238	        nd_append(rec, field);
239	
240	        /* Comma means more fields, semicolon ends */
241	        if (parse_check(TOK_SEMI)) {
242	            parse_advance();
243	            break;
244	        }
245	        if (!parse_match(TOK_COMMA)) {
246	            parse_error("expected , or ; in record DCL");
247	            return rec;
248	        }
249	    }
250	
251	    return rec;
252	}
253	
254	/* Parse a DCL statement. Handles:
255	   - DCL NAME TYPE;
256	   - DCL NAME(dim) TYPE;
257	   - DCL NAME TYPE STATIC;
258	   - DCL NAME TYPE INIT(val);
259	   - DCL 1 NAME, 3 FIELD TYPE, ...;
260	   Returns the root DCL node index. */
261	int parse_dcl(void) {
262	    /* Consume DCL or DECLARE */
263	    if (cur_type != TOK_DCL && cur_type != TOK_DECLARE) {
264	        parse_error("expected DCL");
265	        return NODE_NULL;
266	    }
267	    parse_advance();
268	
269	    /* Check if level-based record: DCL <number> ... */
270	    if (cur_type == TOK_NUM) {
271	        int level = cur_ival;
272	        parse_advance();
273	        return parse_dcl_record(level);
274	    }
275	
276	    /* Simple scalar or array declaration */
277	    int n = parse_dcl_field(0);
278	    if (n == NODE_NULL) return NODE_NULL;
279	
280	    /* Expect semicolon */
281	    parse_expect(TOK_SEMI);
282	
283	    return n;
284	}
285	
286	/* --- Procedure parsing --- */
287	
288	/* Option flag bits for PROC OPTIONS */
289	#define OPT_FREESTANDING 1
290	#define OPT_NAKED        2
291	#define OPT_LEAF         4
292	
293	/* --- Expression parsing --- */
294	
295	/* Operator precedence levels (low to high) */
296	#define PREC_NONE    0
297	#define PREC_OR      1   /* OR (logical) */
298	#define PREC_AND     2   /* AND (logical) */
299	#define PREC_BOR     3   /* | (bitwise OR) */
300	#define PREC_BXOR    4   /* ^ (bitwise XOR) */
301	#define PREC_BAND    5   /* & (bitwise AND) */
302	#define PREC_EQ      6   /* = != */
303	#define PREC_CMP     7   /* < > <= >= */
304	#define PREC_SHIFT   8   /* << >> */
305	#define PREC_ADD     9   /* + - */
306	#define PREC_MUL    10   /* * / */
307	
308	/* Get precedence of a binary operator token */
309	int tok_prec(int type) {
310	    if (type == TOK_OR) return PREC_OR;
311	    if (type == TOK_AND) return PREC_AND;
312	    if (type == TOK_PIPE) return PREC_BOR;
313	    if (type == TOK_CARET) return PREC_BXOR;
314	    if (type == TOK_AMP) return PREC_BAND;
315	    if (type == TOK_EQ) return PREC_EQ;
316	    if (type == TOK_NE) return PREC_EQ;
317	    if (type == TOK_LT) return PREC_CMP;
318	    if (type == TOK_GT) return PREC_CMP;
319	    if (type == TOK_LE) return PREC_CMP;
320	    if (type == TOK_GE) return PREC_CMP;
321	    if (type == TOK_SHL) return PREC_SHIFT;
322	    if (type == TOK_SHR) return PREC_SHIFT;
323	    if (type == TOK_PLUS) return PREC_ADD;
324	    if (type == TOK_MINUS) return PREC_ADD;
325	    if (type == TOK_STAR) return PREC_MUL;
326	    if (type == TOK_SLASH) return PREC_MUL;
327	    return PREC_NONE;
328	}
329	
330	/* Forward declarations */
331	int parse_expr(void);
332	int parse_expr_prec(int min_prec);
333	int parse_stmt(void);
334	
335	/* Parse a primary expression (atom + postfix) */
336	int parse_primary(void) {
337	    /* Unary minus */
338	    if (cur_type == TOK_MINUS) {
339	        parse_advance();
340	        int operand = parse_primary();
341	        return nd_unop(TOK_MINUS, operand);
342	    }
343	    /* Bitwise NOT ~ */
344	    if (cur_type == TOK_TILDE) {
345	        parse_advance();
346	        int operand = parse_primary();
347	        return nd_unop(TOK_TILDE, operand);
348	    }
349	    /* Logical NOT */
350	    if (cur_type == TOK_NOT) {
351	        parse_advance();
352	        int operand = parse_primary();
353	        return nd_unop(TOK_NOT, operand);
354	    }
355	
356	    /* ADDR(expr) -- address-of */
357	    if (cur_type == TOK_ADDR) {
358	        parse_advance();
359	        parse_expect(TOK_LPAREN);
360	        int operand = parse_expr();
361	        parse_expect(TOK_RPAREN);
362	        int n = nd_alloc(NODE_ADDR);
363	        if (n != NODE_NULL) {
364	            nd_left[n] = operand;
365	        }
366	        return n;
367	    }
368	
369	    /* Parenthesized sub-expression */
370	    if (cur_type == TOK_LPAREN) {
371	        parse_advance();
372	        int e = parse_expr();
373	        parse_expect(TOK_RPAREN);
374	        return e;
375	    }
376	
377	    /* Number literal */
378	    if (cur_type == TOK_NUM) {
379	        int n = nd_literal(cur_ival);
380	        parse_advance();
381	        return n;
382	    }
383	
384	    /* String literal */
385	    if (cur_type == TOK_STRING) {
386	        int n = nd_alloc(NODE_LITERAL);
387	        if (n != NODE_NULL) {
388	            nd_set_name(n, cur_text);
389	            nd_type[n] = TYPE_CHAR;
390	        }
391	        parse_advance();
392	        return n;
393	    }
394	
395	    /* Identifier -- may be followed by call(args) */
396	    if (cur_type == TOK_IDENT) {
397	        int nlen = str_len(cur_text);
398	        char *name = arena_alloc(nlen + 1);
399	        if (name) str_copy(name, cur_text);
400	        parse_advance();
401	
402	        /* Function call / array subscript: name(args...) */
403	        if (cur_type == TOK_LPAREN) {
404	            parse_advance();
405	            int args = NODE_NULL;
406	            int tail = NODE_NULL;
407	            if (cur_type != TOK_RPAREN) {
408	                args = parse_expr();
409	                tail = args;
410	                while (cur_type == TOK_COMMA) {
411	                    parse_advance();
412	                    int a = parse_expr();
413	                    if (tail != NODE_NULL) {
414	                        nd_next[tail] = a;
415	                    }
416	                    tail = a;
417	                }
418	            }
419	            parse_expect(TOK_RPAREN);
420	            int n = nd_alloc(NODE_CALL);
421	            if (n != NODE_NULL) {
422	                nd_name[n] = name;
423	                nd_left[n] = args;
424	            }
425	            return n;
426	        }
427	
428	        /* Plain identifier */
429	        int n = nd_alloc(NODE_IDENT);
430	        if (n != NODE_NULL) {
431	            nd_name[n] = name;
432	        }
433	        return n;
434	    }
435	
436	    parse_error("expected expression");
437	    return NODE_NULL;
438	}
439	
440	/* Parse postfix operators: .field and ->field */
441	int parse_postfix(int left) {
442	    while (!parse_err) {
443	        if (cur_type == TOK_DOT) {
444	            parse_advance();
445	            if (cur_type != TOK_IDENT) {
446	                parse_error("expected field name");
447	                return left;
448	            }
449	            int n = nd_alloc(NODE_FIELD_ACCESS);
450	            if (n != NODE_NULL) {
451	                nd_left[n] = left;
452	                nd_set_name(n, cur_text);
453	            }
454	            parse_advance();
455	            left = n;
456	            continue;
457	        }
458	        if (cur_type == TOK_ARROW) {
459	            parse_advance();
460	            if (cur_type != TOK_IDENT) {
461	                parse_error("expected field name after ->");
462	                return left;
463	            }
464	            int n = nd_alloc(NODE_DEREF);
465	            if (n != NODE_NULL) {
466	                nd_left[n] = left;
467	                nd_set_name(n, cur_text);
468	            }
469	            parse_advance();
470	            left = n;
471	            continue;
472	        }
473	        break;
474	    }
475	    return left;
476	}
477	
478	/* Precedence-climbing expression parser */
479	int parse_expr_prec(int min_prec) {
480	    int left = parse_primary();
481	    if (left == NODE_NULL) return NODE_NULL;
482	    left = parse_postfix(left);
483	
484	    while (!parse_err) {
485	        int prec = tok_prec(cur_type);
486	        if (prec == PREC_NONE || prec < min_prec) break;
487	
488	        int op = cur_type;
489	        parse_advance();
490	        int right = parse_expr_prec(prec + 1);
491	        left = nd_binop(op, left, right);
492	        left = parse_postfix(left);
493	    }
494	
495	    return left;
496	}
497	
498	/* Parse a full expression */
499	int parse_expr(void) {
500	    return parse_expr_prec(PREC_OR);
501	}
502	
503	/* --- Statement parsing --- */
504	
505	/* Parse a block of statements (until END or EOF).
506	   Returns a BLOCK node with statements as children. */
507	int parse_block(void) {
508	    int blk = nd_alloc(NODE_BLOCK);
509	    while (!parse_err && cur_type != TOK_END && cur_type != TOK_EOF) {
510	        int s = parse_stmt();
511	        if (s != NODE_NULL) {
512	            nd_append(blk, s);
513	        }
514	    }
515	    return blk;
516	}
517	
518	/* Parse a single statement.
519	   Handles: assignment, IF, DO (WHILE/count/block), CALL,
520	   RETURN, DCL, and expression statements. */
521	int parse_stmt(void) {
522	    int n;
523	    int cond;
524	    int then_body;
525	    int else_body;
526	    int body;
527	    int args;
528	    int tail;
529	    int expr;
530	    int lhs;
531	    int rhs;
532	    int start_expr;
533	    int end_expr;
534	    char *name;
535	    int nlen;
536	
537	    if (parse_err) return NODE_NULL;
538	
539	    /* IF (cond) THEN stmt ELSE stmt */
540	    if (cur_type == TOK_IF) {
541	        parse_advance();
542	        cond = parse_expr();
543	        parse_expect(TOK_THEN);
544	
545	        /* Then branch: DO;...END; block or single statement */
546	        if (cur_type == TOK_DO) {
547	            parse_advance();
548	            parse_expect(TOK_SEMI);
549	            then_body = parse_block();
550	            parse_expect(TOK_END);
551	            parse_expect(TOK_SEMI);
552	        } else {
553	            then_body = parse_stmt();
554	        }
555	
556	        /* Optional ELSE */
557	        else_body = NODE_NULL;
558	        if (cur_type == TOK_ELSE) {
559	            parse_advance();
560	            if (cur_type == TOK_DO) {
561	                parse_advance();
562	                parse_expect(TOK_SEMI);
563	                else_body = parse_block();
564	                parse_expect(TOK_END);
565	                parse_expect(TOK_SEMI);
566	            } else {
567	                else_body = parse_stmt();
568	            }
569	        }
570	
571	        n = nd_alloc(NODE_IF);
572	        if (n != NODE_NULL) {
573	            nd_left[n] = cond;
574	            nd_right[n] = then_body;
575	            nd_ival[n] = else_body;  /* else branch index, or NODE_NULL */
576	        }
577	        return n;
578	    }
579	
580	    /* DO variants */
581	    if (cur_type == TOK_DO) {
582	        parse_advance();
583	
584	        /* DO WHILE (cond); ... END; */
585	        if (cur_type == TOK_WHILE) {
586	            parse_advance();
587	            parse_expect(TOK_LPAREN);
588	            cond = parse_expr();
589	            parse_expect(TOK_RPAREN);
590	            parse_expect(TOK_SEMI);
591	            body = parse_block();
592	            parse_expect(TOK_END);
593	            parse_expect(TOK_SEMI);
594	
595	            n = nd_alloc(NODE_DO_WHILE);
596	            if (n != NODE_NULL) {
597	                nd_left[n] = cond;
598	                nd_right[n] = body;
599	            }
600	            return n;
601	        }
602	
603	        /* DO I = start TO end; ... END; */
604	        if (cur_type == TOK_IDENT) {
605	            nlen = str_len(cur_text);
606	            name = arena_alloc(nlen + 1);
607	            if (name) str_copy(name, cur_text);
608	            parse_advance();
609	
610	            if (cur_type == TOK_EQ) {
611	                parse_advance();
612	                start_expr = parse_expr();
613	                parse_expect(TOK_TO);
614	                end_expr = parse_expr();
615	                parse_expect(TOK_SEMI);
616	                body = parse_block();
617	                parse_expect(TOK_END);
618	                parse_expect(TOK_SEMI);
619	
620	                n = nd_alloc(NODE_DO_COUNT);
621	                if (n != NODE_NULL) {
622	                    nd_name[n] = name;
623	                    nd_left[n] = start_expr;
624	                    nd_ival[n] = end_expr;  /* end expr node index */
625	                    nd_right[n] = body;
626	                }
627	                return n;
628	            }
629	
630	            parse_error("expected = in DO count");
631	            return NODE_NULL;
632	        }
633	
634	        /* DO; ... END; (simple block) */
635	        parse_expect(TOK_SEMI);
636	        body = parse_block();
637	        parse_expect(TOK_END);
638	        parse_expect(TOK_SEMI);
639	        return body;
640	    }
641	
642	    /* CALL proc(args); -- proc name may be a keyword token */
643	    if (cur_type == TOK_CALL) {
644	        parse_advance();
645	        if (!is_alpha(cur_text[0])) {
646	            parse_error("expected proc name after CALL");
647	            return NODE_NULL;
648	        }
649	        nlen = str_len(cur_text);
650	        name = arena_alloc(nlen + 1);
651	        if (name) str_copy(name, cur_text);
652	        parse_advance();
653	
654	        args = NODE_NULL;
655	        if (cur_type == TOK_LPAREN) {
656	            parse_advance();
657	            tail = NODE_NULL;
658	            if (cur_type != TOK_RPAREN) {
659	                args = parse_expr();
660	                tail = args;
661	                while (cur_type == TOK_COMMA) {
662	                    parse_advance();
663	                    expr = parse_expr();
664	                    if (tail != NODE_NULL) nd_next[tail] = expr;
665	                    tail = expr;
666	                }
667	            }
668	            parse_expect(TOK_RPAREN);
669	        }
670	        parse_expect(TOK_SEMI);
671	
672	        n = nd_alloc(NODE_CALL);
673	        if (n != NODE_NULL) {
674	            nd_name[n] = name;
675	            nd_left[n] = args;
676	        }
677	        return n;
678	    }
679	
680	    /* RETURN(expr); or RETURN; */
681	    if (cur_type == TOK_RETURN) {
682	        parse_advance();
683	        expr = NODE_NULL;
684	        if (cur_type == TOK_LPAREN) {
685	            parse_advance();
686	            expr = parse_expr();
687	            parse_expect(TOK_RPAREN);
688	        }
689	        parse_expect(TOK_SEMI);
690	        return nd_return(expr);
691	    }
692	
693	    /* DCL / DECLARE */
694	    if (cur_type == TOK_DCL || cur_type == TOK_DECLARE) {
695	        return parse_dcl();
696	    }
697	
698	    /* Assignment or expression statement.
699	       Parse lvalue (primary + postfix), then check for = */
700	    lhs = parse_primary();
701	    if (lhs == NODE_NULL) return NODE_NULL;
702	    lhs = parse_postfix(lhs);
703	
704	    if (cur_type == TOK_EQ) {
705	        parse_advance();
706	        rhs = parse_expr();
707	        parse_expect(TOK_SEMI);
708	
709	        /* Convert CALL to ARRAY_ACCESS for subscript assignment */
710	        if (nd_kind[lhs] == NODE_CALL) {
711	            nd_kind[lhs] = NODE_ARRAY_ACCESS;
712	        }
713	
714	        return nd_assign(lhs, rhs);
715	    }
716	
717	    /* Expression statement (e.g., bare function call) */
718	    parse_expect(TOK_SEMI);
719	    return lhs;
720	}
