    uart_putstr("lookup COUNT (from proc): ");
    print_int(idx);
    uart_putchar(10);

    idx = sym_lookup("LOCAL");
    uart_putstr("lookup LOCAL: ");
    print_int(idx);
    uart_putchar(10);

