    uart_puts("--- local only ---");
    idx = sym_lookup_local("COUNT");
    uart_putstr("local COUNT: ");
    print_int(idx);
    uart_putchar(10);

    idx = sym_lookup_local("FLAGS");
    uart_putstr("local FLAGS (global only): ");
    print_int(idx);
    uart_putchar(10);

    /* Test 8: dump current scope */
    uart_puts("--- dump proc scope ---");
    sym_dump_scope();

